        '--room-slider-bg': 'rgba(0, 0, 0, 0.1)',
        '--room-slider-track': 'rgba(52, 152, 219, 0.8)',
        '--room-input-bg': 'rgba(255, 255, 255, 0.9)',
        '--room-input-border': 'rgba(0, 0, 0, 0.1)',
