        '--room-title-bg': 'linear-gradient(135deg, rgba(52, 152, 219, 0.9), rgba(41, 128, 185, 0.9))',
        '--room-title-text': 'white',
        '--room-primary-text-bg': 'rgba(255, 255, 255, 0.8)',
