        // 卡片边框主题变量
        '--room-card-border': 'rgba(0, 0, 0, 0.08)',
        // 弹窗内卡片背景色主题变量 - 用于与弹窗背景形成对比
        '--room-popup-card-bg': 'rgba(240, 240, 245, 0.95)',
